def classify_and_ref(span_text):
    if span_text.startswith('لا تُوطَأُ حاملٌ'):
        return 'Hadeeth', {}
    # Ayat based on start words
    if span_text.startswith('وَإِذَا طَلَّقْتُمُ النِّسَاءَ'):
        return 'Aya', {'sura_name':'Al-Baqarah','sura_number':2,'aya_number':232}
    if span_text.startswith('وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ'):
        return 'Aya', {'sura_name':'Al-Baqarah','sura_number':2,'aya_number':228}
    if span_text.startswith('وَإِنْ طَلَّقْتُمُوهُنَّ'):
        return 'Aya', {'sura_name':'Al-Baqarah','sura_number':2,'aya_number':237}
    if span_text.startswith('وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ'):
        return 'Aya', {'sura_name':'Al-Baqarah','sura_number':2,'aya_number':234}
    if span_text.startswith('وَأُولَاتُ الْأَحْمَالِ'):
        return 'Aya', {'sura_name':'At-Talaq','sura_number':65,'aya_number':4}
    return 'Aya', {}

citations = []
for start, end, span_text in segments:
    ctype, aya_ref = classify_and_ref(span_text)
    entry = {
        'span_start': start,
        'span_end': end,
        'span_text': span_text,
        'citation_type': ctype,
        'is_valid': False,
        'aya_reference': aya_ref if ctype=='Aya' else {},
        'hadeeth_reference': {} if ctype=='Aya' else {},
        'corrected_text': 'خطأ',
        'completely_invalid': True
    }
    citations.append(entry)

result = {'citations': citations}
print(json.dumps(result, ensure_ascii=False, indent=2))
